UPDATE sites SET nombre_en = 'Cane Aquapark', tipo_en = 'Site of Interest / Water park', descripcion_en = 'The Acuaparque de la Caña is the large popular water park in Cali, and an institution of Cali recreation for more than four decades. It was born from a generous idea: to give families with fewer resources a spacious and decent place to cool off from the heat of the valley. Inaugurated in 1983 by then-president Belisario Betancur, it was the first park of its kind in southwestern Colombia, and its wave pool—the first in the region—became legend as soon as it opened.\n\nIts 156,000 square meters contain slides with storm names (Tornado, Extremo, Kamikazes), the tarzanera pool, lazy river, amusement rides, fields and stages for concerts. massive. It is managed by the Corporation for Popular Recreation, and hundreds of thousands of Cali residents have passed through its doors every year to visitors as illustrious as Pope John Paul II. More than a spa, it is a piece of the happy memory of several generations.', datos_historicos_en = 'It was inaugurated on July 3, 1983 by President Belisario Betancur, as a popular recreation project administered by the Corporation for Popular Recreation (created in 1979). Its wave pool was the first in the region.', datos_curiosos_en = ARRAY['Pope John Paul II visited it on July 3, 1986, on its third anniversary.', 'It occupies about 156,000 m² and receives about 700,000 visitors a year.', 'Its slides have names like Tornado, Extremo and Kamikazes.']::text[] WHERE id = 'new_1768272722685_455';

UPDATE sites SET nombre_en = 'Delirium', tipo_en = 'Salsa Show', descripcion_en = 'In 2006, when Cali still carried the memory of its hardest times, four women—Andrea Buenaventura, former director of the Cali Fair, along with Eleonora Barberena, Liliana Ocampo and Ángela María Gallo—set out a delirious equation: bringing the salsa of the neighborhoods to the European cabaret format, adding circus and live orchestra. They started with a small platform that today is embarrassing in photos; They ended up creating one of the biggest salsa shows in the world.

Under the Delirio Tent, on the last Friday of each month, the speed of Cali salsa meets acrobats, its own orchestra and a stage performance that has toured more than twenty countries. Behind the brilliance is a foundation with a social purpose: it uses dance and music to transform the lives of young people from sectors affected by violence. It is Cali converted into a creative industry and pride.', importancia_en = 'First and largest salsa cabaret, circus and orchestra show in Colombia; ambassador of quality to the world and model of creative industry with social impact.', datos_historicos_en = 'Founded in May 2006 by four cultural managers from Cali, based on the Circus Tent for All. It is presented on the last Friday of each month and has been recognized as one of the best salsa shows in the world.', datos_curiosos_en = ARRAY['It has performed hundreds of performances in more than 20 countries and has been seen by more than half a million people.', 'Their music is performed live by the Boranda Orchestra; The circus is provided by the Circo Herencias company.', 'Its social program "Paso Firme" works with young people from training centers in vulnerable contexts.']::text[] WHERE id = 's97';

UPDATE sites SET nombre_en = 'Church of La Merced', tipo_en = 'Iglesia', descripcion_en = 'La Merced stands right where Cali was born: here, according to tradition, the founding mass of the city was celebrated in 1536. It is the oldest construction that survives in a city that erased almost all of its colonial architecture, and that is why it functions as a memory capsule: floors and altars in unpolished stone, a main altarpiece in red wood with gold leaf and the image of Our Lady of Mercy, patron saint of the city.\n\nMore than a temple, It is a complex that breathes history: next to the church, the convent of the Augustinian Recollects and the chapels of the Virgen de los Remedios - the "Montañerita Cimarrona", found in the western mountains around 1580 - and the Lateran Christ survive. It was the first property in Cali declared a National Monument. History upon history, like almost everything in this city.', importancia_en = 'The oldest construction in Cali and the symbolic place of its founding; first National Monument of the city and temple of its patron saint.', datos_historicos_en = 'The founding mass of Santiago de Cali was celebrated in its atrium in 1536. In February 1975 the convent complex received the official declaration as a National Monument, being the first property in the city with that recognition. It is in charge of the community of Augustinian Recollect Sisters.', datos_curiosos_en = ARRAY['The rosary that adorns the Virgin was a gift from Pope John Paul II during his visit to Cali in 1986.', 'The Virgin of Mercy received the baton of command from Joaquín de Caycedo y Cuero in 1811 and is considered, symbolically, governor of the city.', 'A host factory still operates in the complex that supplies parishes in the country.']::text[] WHERE id = 's_merced';

UPDATE sites SET nombre_en = 'Church of San Francisco and Mudejar Tower', tipo_en = 'Church/Heritage', descripcion_en = 'The San Francisco complex is a narrative in brick and faith. The Franciscans arrived in Cali around 1750 and built a complex that today includes the convent of San Joaquín, the Chapel of the Immaculate Conception, the imposing neoclassical church and—its jewel—the Mudéjar Tower. That tower of about 23 meters, built around 1772, with its brick bodies cut in trapezoids forming geometries with an oriental air, has been described by the historian Santiago Sebastián as "the most beautiful Mudejar tower in all of America".\n\nIt is the trace of the miscegenation that marked the city: in the tower you can breathe the Spanish-Muslim legacy that crossed the Atlantic, and in the church, the rational thought of the neoclassical. A legend attributes the design to an exiled "Moor", which adds mystery to a unique monument in Colombia. Around, the square and its pigeons do the rest.', importancia_en = 'Franciscan heritage complex and headquarters of the Mudéjar Tower, considered the most beautiful in America; symbol of the architectural fusion of Cali.', datos_historicos_en = 'The convent was built in 1757, with the Chapel of the Immaculate Conception completed around 1764. The Mudéjar Tower dates from around 1772. The current neoclassical church was built between 1803 and 1827, based on designs by the priest Andrés Marcelino Pérez de Arroyo. It was nominated for National Monument status in 1982.', datos_curiosos_en = ARRAY['The Mudéjar Tower is compared to the Giralda in Seville for its brick geometries.', 'The church survived the earthquakes of 1885, 1896 and 1925, preserving its appearance.', 'The adjacent plaza is flanked by the Valle Government building.']::text[] WHERE id = 's_sanfrancisco';

UPDATE sites SET nombre_en = 'Orquideorama', tipo_en = 'Museum/Garden', descripcion_en = 'The Orquideorama is a "living museum" in the north of Cali: a green haven dedicated to the flower that best represents Colombia, the most diverse country in the world for orchids. It has been managed for more than forty years by the Vallecaucana Association of Orchidology, and its architecture—with wide ceilings and wood—evokes the old sugar mills of Valle del Cauca, a nod to the landscape that surrounds it.\n\nHere native species are conserved, studied and exhibited in exhibitions that bring together nearly 180 types of orchids, in addition to a nursery and a collection of trees. It offers cultivation workshops, guided tours for schools and every year it hosts the international exhibition CaliOrquídeas. It is named after the botanist Enrique Pérez Arbeláez, and it is one of those discreet places where the city reconciles itself with its biodiversity.', datos_historicos_en = 'The Vallecaucana Association of Orchidology obtained the land on loan from the Mayor''s Office in 1981, to celebrate the VII International Orchid Exhibition, and built its current headquarters there (designed by architect José Luis Giraldo). It is registered in the Valle del Cauca Museum Network.', datos_curiosos_en = ARRAY['Its architecture is reminiscent of the old sugar mills of the Valley.', 'Every year it holds the international exhibition CaliOrquídeas.', 'It is named after the eminent Colombian botanist Enrique Pérez Arbeláez.']::text[] WHERE id = 'new_1768272723371_563';

UPDATE sites SET nombre_en = 'The Star of Siloam', tipo_en = 'Site of Interest / Viewpoint', descripcion_en = 'At the top of commune 20, on the western slope, a star shines that is much more than a Christmas decoration: it is the symbol of Siloam and its people. It was born from a dream of Professor Alberto Marulanda Palacios, who in the early seventies looked at the hillside covered with small houses lit with candles and oil lamps and saw it as a natural manger that was only missing its star of Bethlehem. After years of community management, the first star—five-pointed and made of guadua—was lit on December 16, 1973 and became visible from the entire city.\n\nToday the star is a beacon and flag of a territory that for decades carried the stigma of violence and that its own young people are transforming into a cultural destination. The Popular Museum of Siloé and the Cooperativo La Estrella collective built the stairs and the viewpoint with their hands, and offer tours that tell the history of the neighborhood, its murals and its music. Climbing up to the star—now renewed—is seeing one of the best views of Cali and, above all, a lesson in resilience.', datos_historicos_en = 'Devised by Professor Alberto Marulanda Palacios, the star was lit for the first time on December 16, 1973, with the support of Emcali. Originally five-pointed, around 2007 it became a sixteen-pointed structure, and in 2025 it was restored to its original five-pointed design with 27,000 LED lights.', datos_curiosos_en = ARRAY['The illuminated hillside evoked a manger; hence the idea of ​​crowning it with a star.', 'The Siloé Popular Museum and the La Estrella Cooperative built the viewpoint and access stairs.', 'You can get there by MíoCable, getting off at the Lleras Camargo station.']::text[] WHERE id = 'new_1768272724018_46';

UPDATE sites SET nombre_en = 'Cañasgordas Club Recreational and Sports Center Comfenalco Valle Delagente', tipo_en = 'Recreation Center', descripcion_en = 'In the south of the city, in the countryside sector of the Lili Valley, the Cañasgordas Club is one of the large recreational centers of the Comfenalco Valle Delagente compensation fund: a space designed for rest and sports for the Valley''s working families. Among large green areas, it offers swimming pools with slides, fourteen clay tennis courts with night lighting, soccer fields with natural and synthetic grass, a restaurant and children''s areas.\n\nAs part of the compensation fund system - a very Colombian social welfare institution - it subsidizes the income of its members, and in recent years it has also opted to become an environmental lung, with rainwater harvesting and solar energy. It is popular recreation in a contemporary key.', datos_historicos_en = 'Managed by the Comfenalco Valle Delagente Family Compensation Fund, in recent years (since 2019) it has been the subject of an expansion plan with new fields, parking lots and sustainable water and energy systems.', datos_curiosos_en = ARRAY['It has fourteen clay tennis courts with lighting for night play.', 'It plans to become an environmental "lung" with rainwater collection and solar energy.', 'Members of categories A and B have access at a subsidized rate, sometimes free.']::text[] WHERE id = 'new_1768272721586_95';

UPDATE sites SET nombre_en = 'Comfandi Pance Country Center', tipo_en = 'Sports/Recreational Center', descripcion_en = 'On the way to Pance, at kilometer 17 of the Cali–Jamundí highway, the Comfandi Campestre Center is a large recreational park of the Comfandi compensation fund, surrounded by nature at the foot of the hills. It is a family day plan: swimming pools and water park, soccer and tennis courts, ecological trails, rowing and fishing lakes, gym and sports school, all among heavily wooded green areas where birds can also be seen.\n\nIt adds adventure attractions such as a 500-meter zip line between towers, and in December it is transformed with its Christmas park. Like the other compensation fund centers, it subsidizes the income of its members and offers programs such as "constructive vacations" for children. It is recreation with a country air, just a few minutes from the city.', datos_historicos_en = 'Administered by the Family Compensation Fund of Valle del Cauca (Comfandi), it is part of its network of recreational centers in the department.', datos_curiosos_en = ARRAY['It has a zip line of about 500 meters between three towers.', 'Its lake is for contemplation and paddling only; Swimming is not allowed in it.', 'During the Christmas season, a Christmas park is set up for families.']::text[] WHERE id = 'new_1768272722278_963';